import axios, {AxiosRequestConfig} from 'axios';
import {
    IHeartGenres,
    IHeartStation,
    GetLocationConfigResponse,
    ResultWithHits,
    Session,
} from './IHeartInterfaces';
import RadioPlayer, {
    GetStationsOptions,
    ListenEvents,
    Locality,
    MediaType,
    Mode,
    SongData,
    StationData,
    VolumePlugin,
} from '../RadioPlayer';
import HLS = require('hls.js');
import {Log} from 'jibo-log';
import querystring = require('querystring');

const CLIENT_VERSION = '1.0.0';
const DEFAULT_NUM_STATIONS_PER_GENRE = 20;
const DEVICE_NAME = 'Jibo';
const INITIAL_HOSTNAME = 'jibo.appliance';
const INIT_ID = 8169;
const NATIONAL_DIGITAL = 575;
const PLAYER = 'iHeartRadioJibo';

const GET_LOCATION_URI = `https://global.api.iheart.com/api/v3/locationConfig?hostname=${INITIAL_HOSTNAME}&version=1.0.0`;

const ENDPOINTS = Object.freeze({
    clientConfig: 'v1/bootstrap/getClientConfig',
    countries: 'v2/content/countries',
    login: 'v1/account/loginOrCreateOauthUser',
    states: 'v2/content/states',
    cities: 'v2/content/cities',
    markets: 'v2/content/markets',
    genres: 'v2/content/liveStationGenres',
    liveStations: 'v2/content/liveStations',
    metadata: 'v1/liveMetaData/getStationTrack',
    reportStreamStarted: 'v1/liveRadio/reportStreamStarted',
});

const DEFAULT_OPTIONS: AxiosRequestConfig = <AxiosRequestConfig>Object.freeze({
    responseType: 'json',
});

// iHeartRadio limits you to 3 frags with a target length of 11s
// and usually returns almost exactly 10 seconds
const HLS_CONFIG: HLS.OptionalConfig = <HLS.OptionalConfig>Object.freeze({
    // This setting actually sets the minimum buffer length, when hls.js will
    // be guaranteed to ask for a new frag
    maxBufferLength: 10,
    // iHeartRadio limits you to 3 frags - it will never allow more than 33s
    // This setting lets hls.js know never to make a request if it's got a
    // nearly full buffer, because there's no point, you won't get a new frag
    maxMaxBufferLength: 33,
});

declare type StationCache = {[callLetters: string]: IHeartStation};


export default class IHeartPlayer extends RadioPlayer {

    private _countryCode: string;
    private _iHeartBaseURI: string;
    private _iHeartHostname: string;
    private _iHeartLog: Log;
    private _iHeartTerminal: number;
    private _initError: string|Error;
    private _initPromise: Promise<void>;
    private _locationConfigError: string|Error;
    private _locationConfigPromise: Promise<void>;
    private _session: Session;
    private _station: IHeartStation;
    private _stationCache: StationCache = {};

    private static _getMediaType(fromIHeart: string): MediaType {
        switch (fromIHeart) {
            case 'M': return MediaType.Music;
            case 'T': return MediaType.Talk;
            case 'O': return MediaType.Other;
            default: return null;
        }
    }

    async init(
        serialNumber: string,
        releaseVersion: string,
        country: string,
        lat: number,
        lng: number,
        listenEvents: ListenEvents,
        volumePlugin: VolumePlugin,
    ): Promise<void> {
        await super.init(
            serialNumber,
            releaseVersion,
            country,
            lat,
            lng,
            listenEvents,
            volumePlugin,
        );
        this._iHeartLog = this._log.createChild('iHeart');
        this._locationConfigPromise = this._promises.wrap(
            this._getLocation().catch(err => this._locationConfigError = err));
        this._initPromise = this._promises.wrap(
            this._init().catch(err => this._initError = err));
    }

    async getCountry(): Promise<string> {
        await this._locationConfigPromise;
        if (this._locationConfigError) {
            throw this._locationConfigError;
        }
        return this._countryCode;
    }

    async getStations(
        options: GetStationsOptions = {},
    ): Promise<StationData[]> {
        await this._initPromise;
        if (this._initError) {
            throw this._initError;
        }
        const limit = options.limit || DEFAULT_NUM_STATIONS_PER_GENRE;
        const genreId = IHeartGenres[options.genreName];
        let stations: IHeartStation[] = await this._promises.wrap(
            this._getLiveStations({
                genreId,
                ...(options.locality === Locality.Local
                    ? {lat: this._lat, lng: this._lng}
                    : {marketId: NATIONAL_DIGITAL}),
                limit,
            }));
        // Move stations with HLS streams to the top, and stations with only
        // PLS streams to the bottom (prefer HLS and then Shoutcast)
        stations = stations.sort((left, right) => {
            if (!left.streams || !right.streams) {
                return left.streams ? -1 : right.streams ? 1 : 0;
            }
            const leftScore =
                left.streams.hls_stream ? 2 :
                left.streams.shoutcast_stream ? 1 :
                0;
            const rightScore =
                right.streams.hls_stream ? 2 :
                right.streams.shoutcast_stream ? 1 :
                0;
            return rightScore - leftScore;
        });
        // Include preferred station for each genre at top of list
        if (options.preferredStation) {
            const station = stations.find(station =>
                station.callLetters === options.preferredStation);
            if (station) {
                stations = stations.sort((left, right) => {
                    const leftScore = left === station ? 1 : 0;
                    const rightScore = right === station ? 1 : 0;
                    return rightScore - leftScore;
                });
            } else {
                const gottenStations = await this._promises.wrap(
                    this._getLiveStations({
                        callLetters: options.preferredStation,
                    }));
                if (gottenStations && gottenStations.length) {
                    stations = [gottenStations[0], ...stations.slice(0, limit - 1)];
                }
            }
        }
        // Add the stations to the local cache by call letters
        stations.forEach((station) => {
            this._stationCache[station.callLetters] = station;
        });
        // Return vendor-neutral station data to the caller
        return stations.map((station): StationData => {
            return {
                band: station.band,
                callLetters: station.callLetters,
                description: station.description,
                frequency: station.freq,
                logoUrl: station.logo,
                name: station.name,
                website: station.website,
            };
        });
    }

    async play(callLetters: string): Promise<void> {
        this._iHeartLog.info(`Playing ${callLetters}`);
        await this._initPromise;
        if (this._initError) {
            throw this._initError;
        }
        const station = this._stationCache[callLetters];
        if (station) {
            this._station = station;
        } else {
            const stations = await this._promises.wrap(this._getLiveStations({
                callLetters,
                limit: 1,
            }));
            if (!stations.length) {
                throw new Error(`Station ${callLetters} not found`);
            }
            this._station =
                this._stationCache[this._station.callLetters] =
                    stations[0];
        }
        return this._promises.wrap(this._streamStation());
    }

    resizeArtwork(uri: string, width: number): string {
        const normalized = Math.min(width, 1920);
        return `http://img.iheart.com/sca/imscale?w=${normalized}&img=${uri}`;
    }

    destroy() {
        super.destroy();
        this._initError = null;
        this._initPromise = null;
        this._locationConfigError = null;
        this._locationConfigPromise = null;
        this._session = null;
        this._station = null;
        this._stationCache = null;
    }

    protected _processHLSMetadata(titleField: string): SongData {
        // Emit Talk for adwizz and Spot Block content
        if (titleField.match(/comment=".*"/)
            || titleField.match(/text=\\?"Spot Block\\?"/)
            || titleField.match(/text=\\?"Spot Block End\\?"/)
        ) {
            return {mediaType: MediaType.Talk};
        }
        // Otherwise, parse the metadata
        const mediaTypeMatch = titleField.match(/song_spot=\\"([MTO])\\"/);
        const mediaType =
            IHeartPlayer._getMediaType(mediaTypeMatch && mediaTypeMatch[1]);
        const titleMatch = titleField.match(/title="(.*?)"/);
        const title = titleMatch && titleMatch[1];
        const artistMatch = titleField.match(/artist="(.*?)"/);
        const artistRaw = artistMatch && artistMatch[1];
        // If there's a pipe in the artist name, show only the first name
        const artist = artistRaw ? artistRaw.split('|')[0].trim() : null;
        const lengthMatch = titleField.match(/length=\\"([0-9:]+?)\\"/);
        const length = lengthMatch && lengthMatch[1];
        const artworkUrlMatch = titleField.match(/amgArtworkURL=\\"(.*?)\\"/);
        const artworkUrlRaw = artworkUrlMatch && artworkUrlMatch[1];
        // Reject iHeart Media default album art
        const artworkUrl = !artworkUrlRaw || artworkUrlRaw.includes('imscale')
            ? null
            : artworkUrlRaw;
        return {mediaType, artist, title, length, artworkUrl};
    }

    protected _processShoutcastMetadata(metadata: any): SongData {
        this._iHeartLog.debug('Processing Shoutcast metadata', metadata);
        if (!metadata.StreamTitle) {
            return {};
        }
        const [artist, rawTitle] = metadata.StreamTitle.split(' - ');
        const title = rawTitle === 'text' ? '' : rawTitle;
        return {artist, title};
    }

    protected _getSidebandData = async (): Promise<SongData> => {
        if (!this._iHeartLog) {
            return;
        }
        const result = await this._promises.wrap(
            this._getSongData({stationId: this._station.id}));
        const metadata = result.trackRestLiteValues
            && result.trackRestLiteValues.length
            && result.trackRestLiteValues[0];
        if (!metadata) {
            return null;
        }
        const fullLength = metadata.trackDuration || 0;
        const minutes = Math.floor(fullLength / 60);
        const seconds = fullLength - minutes * 60;
        // Reject iHeart Media default album art
        const artworkUrl =
            !metadata.imagePath || metadata.imagePath.includes('imscale')
                ? null
                : metadata.imagePath;
        return {
            artist: metadata.artistName,
            title: metadata.title,
            length: `${minutes}:${seconds < 10 ? `0${seconds}` : seconds}`,
            artworkUrl,
        };
    }

    protected _handleStreamError(data?: any): void {
        const streams = this._station.streams;
        if (this._mode === Mode.HLS && streams.shoutcast_stream) {
            this._iHeartLog.info('HLS stream failed; trying Shoutcast');
            this._streamShoutcast(streams.shoutcast_stream, true);
        } else if ((this._mode === Mode.HLS || this._mode === Mode.Shoutcast)
            && streams.pls_stream
        ) {
            this._iHeartLog.info('HLS and Shoutcast failed; trying PLS');
            this._streamPLS(streams.pls_stream, true);
        } else {
            this._iHeartLog.info('All streams failed; emitting error');
            super._handleStreamError(data);
        }
    }

    protected _streamStarted(): void {
        if (!this._session) {
            this._iHeartLog.info('No active session when trying to report start of stream');
            return;
        }
        const params = new URLSearchParams();
        params.append('profileId', this._session.profileId.toString());
        params.append('sessionId', this._session.sessionId);
        params.append('playedFrom', '300');
        params.append('host', this._iHeartHostname);
        params.append('parentId', this._station.id.toString());
        try {
            this._promises.wrap(axios.post(
                this._getURI(ENDPOINTS.reportStreamStarted),
                params,
            ));
        } catch (err) {
            this._iHeartLog.info('Error reporting start of stream', err);
        }
    }

    private async _init() {
        await this._locationConfigPromise;
        if (this._locationConfigError) {
            throw this._locationConfigError;
        }
        await this._promises.wrap(this._login());
    }

    private async _getLocation(): Promise<void> {
        const result = await this._promises.wrap(
            axios.get<GetLocationConfigResponse>(GET_LOCATION_URI));
        this._countryCode = result.data.countryCode.toLowerCase();
        this._iHeartBaseURI = result.data.config.apiUrl;
        this._iHeartHostname = result.data.config.hostName;
        this._iHeartTerminal = result.data.config.terminalId;
    }

    private _getURI(endpoint: string): string {
        return `${this._iHeartBaseURI}/api/${endpoint}`;
    }

    private async _login(): Promise<void> {
        const params = new URLSearchParams();
        params.append('accessToken', 'anon');
        params.append('accessTokenType', 'anon');
        params.append('deviceId', this._deviceId);
        params.append('deviceName', `anon${this._deviceId}`);
        params.append('host', this._iHeartHostname);
        params.append('oauthUuid', this._deviceId);
        params.append('oauthoverride', 'false');
        this._session = await this._promises.wrap(
            this._post<Session>(ENDPOINTS.login, params));
        this._iHeartLog.debug('login completed', this._session);
    }

    private async _get<T>(
        endpoint: string,
        options: AxiosRequestConfig = undefined,
    ): Promise<T> {
        //this._iHeartLog.debug(uri, JSON.stringify(Object.assign({}, DEFAULT_OPTIONS, options)));
        options = {...options};
        options.headers = {
            ...options.headers,
            'X-hostName': this._iHeartHostname,
        };
        const result = await axios.get<T>(
            this._getURI(endpoint),
            Object.assign({}, DEFAULT_OPTIONS, options));
        return result.data;
    }

    private async _getHits<T>(
        endpoint: string,
        options: AxiosRequestConfig = undefined,
    ): Promise<T[]> {
        const result = await this._promises.wrap(
            this._get<ResultWithHits<T>>(endpoint, options));
        return result.hits;
    }

    private async _post<T>(
        endpoint: string,
        data: any = undefined,
        options: AxiosRequestConfig = undefined,
    ): Promise<T> {
        //this._iHeartLog.debug(uri, JSON.stringify(Object.assign({}, DEFAULT_OPTIONS, options)));
        options = {...options};
        options.headers = {
            ...options.headers,
            'X-hostName': this._iHeartHostname,
        };
        const result = await this._promises.wrap(axios.post<T>(
            this._getURI(endpoint),
            data,
            Object.assign({}, DEFAULT_OPTIONS, options),
        ));
        return result.data;
    }

    private _getLiveStations(params?: any): Promise<IHeartStation[]> {
        return this._promises.wrap(
            this._getHits<IHeartStation>(ENDPOINTS.liveStations, {params}));
    }

    private _getSongData(params?: any): Promise<any> {
        return this._promises.wrap(
            this._get<any>(ENDPOINTS.metadata, {params}));
    }

    private async _streamStation(): Promise<void> {
        const streams = this._station.streams;
        if (streams.secure_hls_stream){
            return this._promises.wrap(this._iHeartStreamHLS(streams.secure_hls_stream));
        } else if (streams.hls_stream) {
            return this._promises.wrap(this._iHeartStreamHLS(streams.hls_stream));
        // } else if (streams.secure_shoutcast_stream) {
        //     //This stream type doesnt seem to work on any station
        //     return this._promises.wrap(this._streamShoutcast(
        //         streams.secure_shoutcast_stream));
        } else if (streams.shoutcast_stream) {
            return this._promises.wrap(this._streamShoutcast(
                streams.shoutcast_stream));
        // } else if (streams.secure_pls_stream) {
        //     //This stream type is unreliable
        //     return this._promises.wrap(this._streamPLS(
        //         streams.secure_pls_stream));
        } else if (streams.pls_stream) {
            return this._promises.wrap(this._streamPLS(
                streams.pls_stream));
        }
        throw new Error('No compatible stream found');
    }

    private async _iHeartStreamHLS(stream: string): Promise<void> {
        const qs = querystring.stringify({
            iheartradioversion: CLIENT_VERSION,
            Deviceid: this._deviceId,
            clienttype: DEVICE_NAME,
            osVersion: this._releaseVersion,
            devicename: DEVICE_NAME,
            callLetters: this._station.callLetters,
            Streamid: this._station.id,
            terminalid: this._iHeartTerminal,
            init_id: INIT_ID,
            fb_broadcast: 0,
            at: 0,
            pname: DEVICE_NAME,
            listenerId: this._deviceId,
            amsparams: `playerid:${PLAYER};skey=${new Date().toISOString()}`,
        });
        const uri = `${stream}?${qs}`;
        return this._promises.wrap(this._streamHLS(uri, HLS_CONFIG));
    }
}
