import axios from 'axios';
import {CancelTokenSession, PromiseUtils} from 'jibo-cai-utils';
import crypto = require('crypto');
import dns = require('dns');
import {Event} from 'jibo-typed-events';
import {EventEmitter} from 'events';
import HLS = require('hls.js');
import http = require('http');
import icecast = require('icecast');
import {Log} from 'jibo-log';
import {Stream} from 'stream';
import url = require('url');

const HJ_VOLUME = 1;
const VOLUME_NORMAL = 0.06;

// In milliseconds
const DNS_TIMEOUT = 5000;
const STREAM_TIMEOUT = 10000;

const promisify = PromiseUtils.promisify;

/**
 * Enum of radio media types.
 * @typedef MediaType
 * @prop Music
 * @prop Talk
 * @prop Other
 */
export enum MediaType {
    Music = 'Music',
    Talk = 'Talk',
    Other = 'Other',
}

/**
 * @interface SongData
 * @prop [mediaType] {MediaType}
 * @prop [artist] {string}
 * @prop [title] {string}
 * @prop [artworkUrl] {string}
 * @prop [length] {string}
 */
export interface SongData {
    mediaType?: MediaType;
    artist?: string;
    title?: string;
    artworkUrl?: string;
    length?: string;
}

/**
 * @interface StationData
 * @prop band {string}
 * @prop callLetters {string}
 * @prop description {string}
 * @prop frequency {string}
 * @prop logoUrl {string}
 * @prop name {string}
 * @prop website {string}
 */
export interface StationData {
    band: string;
    callLetters: string;
    description: string;
    frequency: string;
    logoUrl: string;
    name: string;
    website: string;
}

/**
 * Enum of radio-play modes
 * @typedef Mode
 * @prop HLS
 * @prop Shoutcast
 * @prop PLS
 * @intdocs
 */
export enum Mode {
    HLS = 'HLS',
    Shoutcast = 'Shoutcast',
    PLS = 'PLS',
}

/**
 * Enum of supported localities when searching for live stations
 * @typedef Locality
 * @prop Local
 * @prop National
 */
export enum Locality {
    Local = 'Local',
    National = 'National',
}

/**
 * Options provided to RadioPlayer#getStations
 * @interface GetStationsOptions
 * @prop [genreName] {string} The name of the genre for filteriing the station results
 * @prop [locality] {Locality} Limit the results to national or local stations
 * @prop [limit] {number} Limit the results to this amount
 * @prop [preferredStation] {string} The call letters of the station preferred by the end-user, or the default station for the genre
 */
export interface GetStationsOptions {
    genreName?: string;
    locality?: Locality;
    limit?: number;
    preferredStation?: string;
}

/**
 * Generic interface of jibo.volume properties that we use
 * @interface VolumePlugin
 * @prop currentVolume {number}
 * @intdocs
 */
export interface VolumePlugin extends EventEmitter {
    currentVolume: number;
}

/**
 * Generic interface of websocket responses emitted from jibo.gl.events.noMatch
 * @interface WSResponse<T = any>
 * @prop status {string}
 * @prop message {string}
 * @prop id {string}
 * @prop result {T}
 * @prop moreinfo {string}
 * @intdocs
 */
export interface WSResponse<T = any> {
    status: string;
    message: string;
    id: string;
    result: T;
    moreinfo: string;
}

/**
 * Generic interface of the jibo.jetstream.events and jibo.globalEvents used in RadioPlayer
 * @interface ListenEvents
 * @prop hjHeard {Event<void>}
 * @prop hjOnly {Event<void>}
 * @prop noMatch {Event<WSResponse<jibo.gl.NoMatchResults>>}
 * @prop noGlobalMatch {Event<any>}
 * @prop nonInterruptingGlobal {Event<void>}
 * @intdocs
 */
export interface ListenEvents {
    hjHeard: Event<void>;
    hjOnly: Event<any>;
    noGlobalMatch: Event<any>;
    nonInterruptingGlobal: Event<void>;
}

const DEVICE_ID_SALT = '6464e9ec0098c3e04d65392f607b9ed9';


/**
 * This is an abstract base class, which cannot be instantiated directly;
 * instead, use an implementation of this class, like IHeartPlayer
 * @class RadioPlayer
 */
export default abstract class RadioPlayer extends EventEmitter {

    protected static _hash(name: string): string {
        const shasum = crypto.createHash('sha256');
        shasum.update(`${DEVICE_ID_SALT}-${name}`);
        return shasum.digest('hex');
    }

    private static _songDataDifferent(
        left: SongData,
        right: SongData,
    ): boolean {
        // If one is null but not the other, they're different
        return !!left && !right
            || !left && !!right
            // Now that we've dodged null reference exceptions, compare
            // the properties we care about for differences
            || left.mediaType !== right.mediaType
            || left.artist !== right.artist
            || left.title !== right.title;
    }

    private static _promiseTimeout<T>(
        promise: Promise<T>,
        millis: number,
    ): Promise<T> {
        return Promise.race([
            promise,
            new Promise<T>((_, reject) =>
                setTimeout(() => reject(new Error('Timeout')), millis)),
        ]);
    }

    protected _deviceId: string;
    protected _lat: number;
    protected _lng: number;
    protected _log: Log;
    protected _mediaTagPlayPromise: Promise<void>;
    protected _mode: Mode;
    protected _promises = new CancelTokenSession();
    protected _releaseVersion: string;

    private _audio: HTMLAudioElement;
    private _country: string;
    private _hls: HLS;
    private _hlsURI: string;
    private _icecastClient: Stream;
    private _isCurrentlySpeaking: boolean = false;
    private _lastSongData: SongData;
    private _listenEvents: ListenEvents;
    private _playPromise: Promise<void>;
    private _playReject: (reason?: any) => void;
    private _playResolve: (value?: void | PromiseLike<void>) => void;
    private _plsStreams: string[];
    private _plsStreamFirstIndex: number;
    private _plsStreamIndex: number;
    private _pollSongData: NodeJS.Timer;
    private _recoveringMedia: NodeJS.Timer;
    //private _recoveringNetwork: boolean;
    private _shoutcastServer: http.Server;
    private _songDataSession: CancelTokenSession;
    private _songDataTimers: NodeJS.Timer[] = [];
    private _swappingAudioCodec: boolean;
    private _video: HTMLVideoElement;
    private _volumePlugin: VolumePlugin;

    constructor() {
        super();
        if (!HLS.isSupported()) {
            throw new Error('Oh no! HTTP Live Streaming isn\'t supported!');
        }
    }

    /**
     * Initialize the RadioPlayer: implementations can override this, but must
     * call super.init() to ensure this code runs
     * @param  {string}        serialNumber   Pass in the result from jibo.systemManager.getIdentity()
     * @param  {string}        releaseVersion Pass in jibo.versions.release
     * @param  {string}        country        Pass in jibo.utils.Location.jiboHome.country;
     * @param  {number}        lat            Pass in jibo.utils.Location.jiboHome.lat
     * @param  {number}        lng            Pass in jibo.utils.Location.jiboHome.lng
     * @param  {ListenEvents}  listenEvents   Pass in jibo.gl.events
     * @param  {VolumePlugin}  volumePlugin   Pass in jibo.volume
     * @return {Promise<void>}                Resolves when all init steps are complete
     */
    async init(
        serialNumber: string,
        releaseVersion: string,
        country: string,
        lat: number,
        lng: number,
        listenEvents: ListenEvents,
        volumePlugin: VolumePlugin,
    ): Promise<void> {
        this._deviceId = RadioPlayer._hash(serialNumber);
        this._releaseVersion = releaseVersion;
        this._country = country;
        this._lat = lat;
        this._lng = lng;
        this._listenEvents = listenEvents;
        // Lower the volume when HJ is heard
        this._listenEvents.hjHeard.on(this._hjHeard);
        // Raise the volume when Jibo's done listening, conditionally
        // We don't want to bring the volume back up on skill-switch
        // which conveniently includes station changes; the player will
        // bring volume back up to max on play start of the new station
        this._listenEvents.hjOnly.on(this._listenFinished);
        this._listenEvents.noGlobalMatch.on(this._listenFinished);
        this._listenEvents.nonInterruptingGlobal.on(this._listenFinished);
        // Set the radio volume to match the overall Jibo volume, resulting
        // in a square curve that lowers the radio volume at the low end
        this._volumePlugin = volumePlugin;
        this._volumePlugin.on('change', this._volumeChanged);
        this._log = new Log('Jibo.Radio');
    }

    async getCountry(): Promise<string> {
        return this._country;
    }

    /**
     * Get a list of stations matching the options provided
     * @method RadioPlayer#getStations
     * @param  {GetStationsOptions} options The search options to use
     * @return {Promise<StationData[]>} Resolves to a list of stations matching the options provided
     */
    abstract getStations(options: GetStationsOptions): Promise<StationData[]>;

    /**
     * Play the provided radio station; call letters may be retrieved from
     * getStations() results. Abstract method must be implemented;
     * implementations must call _streamHLS, _streamShoutcast, or _streamPLS
     * @method RadioPlayer#play
     * @param  {string} callLetters The call letters of the station to play
     * @return {Promise<void>} Resolves when the station actually starts streaming
     */
    abstract play(callLetters: string): Promise<void>;

    /**
     * Replace a URL to artwork with one that will resize the artwork to the
     * dimension provided. Implementations can override this; the default
     * behavior simply returns the provided URL back, unaltered.
     * @method RadioPlayer#resizeArtwork
     * @param  {string} url
     * @param  {number} width
     * @return {string}
     */
    resizeArtwork(uri: string, width: number): string {
        return uri;
    }

    /**
     * Pauses the current stream; not expected to be overridden
     * @method RadioPlayer#pause
     * @return {Promise<void>}
     */
    async pause(): Promise<void> {
        // If a media tag is paused while a Promise returned from its play
        // method is outstanding, an unhandled exception is thrown, so avoid
        // this situation by waiting for its play Promise to resolve or reject
        if (this._mediaTagPlayPromise) {
            try {
                await this._mediaTagPlayPromise;
            } catch (err) {
                // Don't return if it rejects; log a warning, and pause anyway
                this._log.info('HTMLMediaElement#play rejected', err);
            }
            // Allow this to be garbage collected
            this._mediaTagPlayPromise = null;
        }
        // Actually pause the media element
        if (this._audio) {
            this._audio.pause();
        }
        if (this._video) {
            this._video.pause();
        }
    }

    /**
     * Begin playing the current stream, or resume the paused stream
     * @method RadioPlayer#resume
     * @return {Promise<void>}
     */
    async resume(): Promise<void> {
        // Nothing to resume if a media tag for the stream hasn't been created
        if (this._mode === 'HLS' && !this._video
            || this._mode !== 'HLS' && !this._audio
        ) {
            return;
        }
        // Pause any currently-playing stream before playing this one; allows
        // music to continue streaming until the new stream is ready to begin
        try {
            await this.pause();
        } catch (err) {
            // Continue even if pause throws an error
            this._log.info('Error pausing stream', err);
        }
        // Keep track of the Promise so pause() can await it to avoid an
        // unhandled exception in that case
        this._mediaTagPlayPromise = this._promises.wrap(
            this._mode === Mode.HLS
                ? this._video.play()
                : this._audio.play()
        ).catch(err => {
            this._log.info('HTMLMediaElement#play rejected', err);
            if (this._mode === Mode.HLS) {
                this._handleVideoError();
            } else {
                this._handleAudioError();
            }
        });
    }

    /**
     * Stop a stream, cancel related Promises and timers, remove related event
     * listeners, and release all related resources for garbage collection.
     * An implementation may override this, but must await super.stop().
     * @method RadioPlayer#stop
     * @return {Promise<void>}
     */
    async stop(): Promise<void> {
        this._lastSongData = undefined;
        // Cancel any song-data fetching for the previous song
        if (this._songDataSession) {
            this._songDataSession.cancel();
            this._songDataSession = null;
        }
        // Cancel any song-data fethcing timers
        this._songDataTimers.forEach(clearTimeout);
        this._songDataTimers = [];
        if (this._pollSongData) {
            clearTimeout(this._pollSongData);
            this._pollSongData = null;
        }
        // Close the local Shoutcast server if we're reading Icecast data
        this._icecastClient = null;
        if (this._shoutcastServer) {
            this._shoutcastServer.close();
            this._shoutcastServer = null;
        }
        // Remove event handlers and kill the HLS client
        if (this._hls) {
            this._hls.off(HLS.Events.ERROR, this._handleHLSErrors);
            this._hls.off(HLS.Events.FRAG_PARSING_METADATA, this._hlsFragParsing);
            this._hls.off(HLS.Events.MANIFEST_PARSED, this._hlsManifestParsed);
            this._hls.off(HLS.Events.MEDIA_ATTACHED, this._hlsMediaAttached);
            this._hls.destroy();
            this._hls = null;
        }
        // Continue even if pause throws an error. Do this last, since pausing
        // is an async process, because HTMLMediaElement#play is async and
        // attempting to pause the tag while its play Promise is outstanding
        // will throw an unhandled exception
        try {
            await this.pause();
        } catch (err) {
            this._log.info('Error during pause', err);
        }
        // Remove media-tag event handlers and release them
        if (this._audio) {
            this._audio.removeEventListener('loadeddata', this._handleMediaPlaying);
            this._audio.removeEventListener('stalled', this._handleAudioError);
            this._audio.removeEventListener('error', this._handleAudioError);
            this._audio = null;
        }
        if (this._video) {
            this._video.removeEventListener('loadeddata', this._handleMediaPlaying);
            this._video.removeEventListener('error', this._handleVideoError);
            this._video = null;
        }
    }

    /**
     * Cancel all Promises and event listenrs and release all used memory
     * @method RadioPlayer#destroy
     * @return {void}
     */
    destroy(): void {
        this._listenEvents.hjHeard.off(this._hjHeard);
        this._listenEvents.hjOnly.off(this._listenFinished);
        this._listenEvents.noGlobalMatch.off(this._listenFinished);
        this._listenEvents.nonInterruptingGlobal.off(this._listenFinished);
        this._log = null;
        this._playPromise = null;
        this._playReject = null;
        this._playResolve = null;
        this._promises.cancel();
        this._promises = null;
        this._volumePlugin.removeListener('change', this._volumeChanged);
    }

    /**
     * Stop any current stream, cancel Promises and event listeners, and
     * release all memory used by the RadioPlayer for garbage collection
     * @method RadioPlayer#stopAndDestroy
     * @return {Promise<void>}
     */
    async stopAndDestroy(): Promise<void> {
        // Make sure we continue even if stop throws an error
        try {
            await this.stop();
        } catch (err) {
            this._log.warn('Error when stopping during cleanup', err);
        }
        this.destroy();
    }

    // Abstract methods to process metadata from an HLS fragment or Icecast
    // emission. Since the metadata itself is implementation-specific, these
    // are required to be implemented by every implementation
    protected abstract _processHLSMetadata(titleField: string): SongData;
    protected abstract _processShoutcastMetadata(titleField: string): SongData;

    // Must be implemented to fetch song data from sideband, if available
    protected abstract _getSidebandData: () => Promise<SongData>;


    // Give implementations the ability to define fallback behavior rather
    // than giving up on a station, in case there is more than one stream type
    // available for that station
    protected _handleStreamError(err?: any): void {
        this._rejectOrEmit(err);
    }

    // Implementations must provide a #play() method which calls _streamHLS,
    // _streamShoutcast, or _streamPLS.
    protected async _streamHLS(
        uri: string,
        config: HLS.OptionalConfig = undefined,
        failover = false,
    ): Promise<void> {
        this._log.debug('_streamHLS called', uri, config);
        await this.stop();
        this._mode = Mode.HLS;
        this._hlsURI = uri;
        this._hls = new HLS(Object.assign({}, config));
        // Load the source once the video tag is attached
        this._hls.on(HLS.Events.MEDIA_ATTACHED, this._hlsMediaAttached);
        // Begin play once the manifest is downloaded and parsed
        this._hls.on(HLS.Events.MANIFEST_PARSED, this._hlsManifestParsed);
        // Process song metadata when a frag is added to the buffer
        this._hls.on(HLS.Events.FRAG_PARSING_METADATA, this._hlsFragParsing);
        // Hook up error handler
        this._hls.on(HLS.Events.ERROR, this._handleHLSErrors);
        // Attach the video element to begin the sequence; return a Promise,
        // and keep a reference to the resolve function to call when play
        // actually begins
        this._video = document.createElement('video');
        this._video.addEventListener('loadeddata', this._handleMediaPlaying);
        this._video.addEventListener('error', this._handleVideoError);
        if (failover) {
            return this._hls.attachMedia(this._video);
        }
        // Return an unresolved Promise, and then kick off the sequence
        // that will eventually start the stream and resolve that Promise
        return this._promises.wrap(RadioPlayer._promiseTimeout(
            this._setStreamPromiseHandlers(() => {
                this._hls.attachMedia(this._video);
            }),
            STREAM_TIMEOUT,
        ));
    }

    // Tries to fill in missing fields from in-stream song data from sideband
    private async _fillMissingSongData(songData: SongData): Promise<SongData> {
        songData = songData || {};
        // If the MediaType is Music and there are empty fields,
        // retrieve the missing fields from the sideband data instead
        if (!songData.mediaType || songData.mediaType === MediaType.Music) {
            // Pre-test fetching the artwork URL headers, so we can replace
            // the URL with sideband if it doesn't return an OK status
            let artworkUrl: string = null;
            if (songData.artworkUrl) {
                try {
                    const response = await axios.head(songData.artworkUrl);
                    if (response.status >= 200 && response.status < 300) {
                        artworkUrl = songData.artworkUrl;
                    }
                } catch (err) {
                    artworkUrl = null;
                }
            }
            // Only bother fetching data if something is missing
            if (!songData.artist || !artworkUrl || !songData.title) {
                this._log.info('Stream data was missing some fields; fetching from sideband');
                this._log.info('Stream data', songData);
                const sidebandData = await this._getSidebandData();
                if (sidebandData) {
                    this._log.info('Sideband data', sidebandData);
                    if (!artworkUrl && sidebandData.artworkUrl) {
                        songData.artworkUrl = sidebandData.artworkUrl;
                    }
                    if (!songData.artist && sidebandData.artist) {
                        songData.artist = sidebandData.artist;
                    }
                    if (!songData.title && sidebandData.artist) {
                        songData.title = sidebandData.title;
                    }
                    this._log.info('Combined data', songData);
                }
            } else {
                this._log.info('No sideband data found');
            }
        }
        return songData;
    }

    private async _emitSongData(
        songData: SongData,
        fromSideband = false,
    ): Promise<void> {
        const firstTime = this._lastSongData === undefined;
        // If we've destroyed the player, do nothing
        if (!this._log
            // If this data and the last data are both null, avoid null
            // references in the conditions below
            || !songData && !this._lastSongData
            // If this isn't the first time through, and the data is the same
            // as last time, do nothing
            || !firstTime && !RadioPlayer._songDataDifferent(
                songData,
                this._lastSongData,
            )
        ) {
            return;
        }
        // Keep track of the unfilled song data, so we don't compare to filled
        // and try to fetch sideband every frame
        this._lastSongData = songData;
        // If there's any data missing, try to fill it with a sideband call
        this._songDataSession = new CancelTokenSession();
        let filledSongData = songData;
        if (!fromSideband) {
            try {
                filledSongData = await this._songDataSession.wrap(
                    this._fillMissingSongData(songData));
            } catch (err) {
                this._log.info('Failed to get sideband data', err);
            }
        }
        // If this is HTTP Live Streaming (HLS), wait until the end of the
        // buffer before emitting; but if streaming just started, emit
        // immediately instead
        if (this._mode === Mode.HLS && this._video && !firstTime) {
            // Subtract the current time from the buffer end time to
            // determine what remains
            const end = this._video.buffered.length
                ? this._video.buffered.end(this._video.buffered.length - 1)
                : 0;
            const current = this._video.currentTime;
            const buffer = end - current;
            const emitIn = end === 0 ? 0 : buffer + 5;
            this._log.debug(`end: ${end}, current: ${current}, buffer: ${buffer}`);
            this._log.debug(`Will emit songData in ${emitIn} seconds`, filledSongData);
            // Wrap the timeout callback so we cancel it on skill exit
            const emitData = () => {
                this.emit('song-data', filledSongData);
                this._songDataTimers.shift();
            };
            this._songDataTimers.push(setTimeout(
                this._promises.wrapCallback(emitData),
                emitIn * 1000,
            ));
        }
        // If it's not HLS, or we just started, emit the information right
        // away
        else {
            this.emit('song-data', filledSongData);
        }
    }

    // Implementations must provide a #play() method which calls _streamHLS,
    // _streamShoutcast, or _streamPLS.
    protected async _streamShoutcast(
        uri: string,
        failover = false,
    ): Promise<void> {
        this._log.debug(`Streaming Shoutcast from ${uri}; failover ${failover}`);
        await this.stop();
        this._mode = Mode.Shoutcast;
        try {
            const hostname = url.parse(uri).hostname;
            await this._promises.wrap(RadioPlayer._promiseTimeout(
                promisify(cb => dns.resolve(hostname, cb)), DNS_TIMEOUT));
        } catch (err) {
            this._log.info('Shoutcast server hostname failed to resolve', err);
            return failover
                ? this._handleAudioError()
                : this._setStreamPromiseHandlers(
                    // Ensure startStream executes asynchronously, so rejection
                    // handlers can be added, before executing this code
                    setImmediate(() => this._handleAudioError()));
        }
        this._icecastClient = await this._promises.wrap<Stream>(
            promisify(cb => icecast.get(uri, cb), false));
        this._icecastClient.on('metadata', (songData) => this._emitSongData(
            this._processShoutcastMetadata(icecast.parse(songData))));
        this._icecastClient.on('error', this._handleAudioError);
        this._shoutcastServer = http.createServer((req, res) => {
            res.setHeader('Cache-Control', 'no-cache, no-store');
            res.setHeader('Connection', 'close');
            res.setHeader('Content-Type', 'audio/aac');
            res.setHeader('Expires', 'Mon, 26 Jul 1997 05:00:00 GMT');
            res.setHeader('Pragma', 'no-cache');
            this._icecastClient.pipe(res);
        });
        this._shoutcastServer.listen(0, '127.0.0.1');
        await promisify(cb => this._shoutcastServer.once('listening', cb));
        if (!this._shoutcastServer) {
            return;
        }
        const port = this._shoutcastServer.address().port;
        this._log.debug(`Shoutcast server listening on ${port}`);
        this._audio = document.createElement('audio');
        this._audio.addEventListener('loadeddata', this._handleMediaPlaying);
        this._audio.addEventListener('stalled', this._handleAudioError);
        this._audio.addEventListener('error', this._handleAudioError);
        this._audio.src = `http://127.0.0.1:${port}/`;
        this._volume = this._volumePlugin.currentVolume;
        if (failover) {
            return this.resume();
        }
        // Return an unresolved Promise, and then start the stream, which
        // will eventually resolve that Promise
        return this._promises.wrap(RadioPlayer._promiseTimeout(
            this._setStreamPromiseHandlers(() => this.resume()),
            STREAM_TIMEOUT,
        ));
    }

    // Implementations must provide a #play() method which calls _streamHLS,
    // _streamShoutcast, or _streamPLS.
    protected async _streamPLS(
        uri: string,
        failover = false,
    ): Promise<void> {
        this._log.debug(`Streaming PLS from ${uri}`);
        await this.stop();
        this._mode = Mode.PLS;
        try {
            const plsContent: string =
                (await this._promises.wrap(axios.get(uri))).data;
            this._plsStreams = plsContent.split('\n')
                .filter(url => url.startsWith('File'))
                .map(url => url.split('=', 2)[1]);
            this._plsStreamFirstIndex = this._plsStreamIndex =
                Math.floor(Math.random() * this._plsStreams.length);
        } catch (err) {
            return this._handleAudioError();
        }
        this._audio = document.createElement('audio');
        this._audio.addEventListener('loadeddata', this._handleMediaPlaying);
        this._audio.addEventListener('stalled', this._handleAudioError);
        this._audio.addEventListener('error', this._handleAudioError);
        this._volume = this._volumePlugin.currentVolume;
        if (failover) {
            return this.resume();
        }
        // Return an unresolved Promise, and then start the stream, which
        // will eventually resolve that Promise
        return this._promises.wrap(RadioPlayer._promiseTimeout(
            this._setStreamPromiseHandlers(() => this._playPLSStream()),
            STREAM_TIMEOUT,
        ));
    }

    // Called when a stream successfully begins. The default behavior does
    // nothing, but implementations may override this behavior, for instance
    // to report to the stream start to a provider to meet their advertising
    // requirements
    protected _streamStarted(): void {/* */}

    public setCurrentlySpeaking(isCurrentlySpeaking: boolean) {
        this._isCurrentlySpeaking = isCurrentlySpeaking;
        this._volume = isCurrentlySpeaking ? HJ_VOLUME : this._volumePlugin.currentVolume;
    }

    private get _volume(): number {
        return this._audio ? this._audio.volume / VOLUME_NORMAL
            : this._video ? this._video.volume / VOLUME_NORMAL
            : 0;
    }

    private set _volume(value: number) {
        if (value < 1 || value > 10) {
            throw new Error(`Value must be between 1 and 10, inclusive`);
        }
        const volume = value * VOLUME_NORMAL;
        if (this._audio) {
            this._audio.volume = volume;
        }
        if (this._video) {
            this._video.volume = volume;
        }
    }

    private _hjHeard = () => {
        this._volume = HJ_VOLUME;
    }

    private _listenFinished = () => {
        if (!this._isCurrentlySpeaking) {
            this._volume = this._volumePlugin.currentVolume;
        }
    }

    private _volumeChanged = (volume: number) => {
        this._volume = volume;
    }

    private async _playPLSStream(): Promise<void> {
        this._audio.src = this._plsStreams[this._plsStreamIndex];
        await this.resume();
        const getAndEmitData = async () => {
            const data = await this._getSidebandData();
            await this._emitSongData(data, true);
            setTimeout(getAndEmitData, 1000);
        };
        // Kick off the loop
        getAndEmitData();
    }

    private async _nextPLSStream(data?: any): Promise<void> {
        const oldIndex = this._plsStreamIndex;
        if (!this._plsStreams) {
            return this._handleStreamError(data);
        }
        if (++this._plsStreamIndex === this._plsStreams.length) {
            this._plsStreamIndex = 0;
        }
        if (this._plsStreamIndex !== this._plsStreamFirstIndex) {
            this._log.info(`PLS stream ${oldIndex} failed`);
            await this._playPLSStream();
        } else {
            this._handleStreamError(data);
        }
    }

    private _hlsMediaAttached = (): void => {
        if (this._hls) {
            this._hls.loadSource(this._hlsURI);
        }
    }

    private _hlsManifestParsed = (event, data): void => {
        if (this._hls) {
            this._log.info(`Manifest loaded, found ${data.levels.length} quality levels`);
            this._mode = Mode.HLS;
            this._volume = this._volumePlugin.currentVolume;
            this.resume();
        }
    }

    private _hlsFragParsing = async (
        event: string,
        fragment: HLS.Data,
    ): Promise<void> => {
        this._log.debug(event, fragment);
        if (fragment.frag.title) {
            try {
                this._emitSongData(this._processHLSMetadata(fragment.frag.title));
            } catch (err) {
                this._log.info('Problem parsing HLS stream metadata; trying sideband', err);
                this._emitSongData(await this._getSidebandData(), true);
            }
        }
    }

    private _handleHLSErrors = (event, data): void => {
        if (!this._hls) {
            return;
        }
        if (!data.fatal) {
            this._log.info('HLS warning', data);
            return;
        }
        switch (data.type) {
            // case HLS.ErrorTypes.NETWORK_ERROR:
                // if (!this._recoveringNetwork) {
                //     this._log.info('Restarting load to correct network error', data);
                //     this._recoveringNetwork = true;
                //     setTimeout(() => this._recoveringNetwork = false, 2000);
                //     this._hls.startLoad();
                // } else {
                //     this._recoveringNetwork = false;
                // this._handleStreamError(data);
                // }
                // break;
            case HLS.ErrorTypes.MEDIA_ERROR:
                if (!this._recoveringMedia) {
                    this._log.info('Trying to recover from media error', data);
                    this._recoveringMedia =
                        setTimeout(() => this._recoveringMedia = null, 2000);
                    this._hls.recoverMediaError();
                } else if (!this._swappingAudioCodec) {
                    this._log.info('Swapping audio codec this time, then trying again to recover from media error', data);
                    clearTimeout(this._recoveringMedia);
                    this._recoveringMedia = null;
                    this._swappingAudioCodec = true;
                    setTimeout(() => this._swappingAudioCodec = false, 2000);
                    this._hls.swapAudioCodec();
                    this._hls.recoverMediaError();
                } else {
                    this._recoveringMedia = null;
                    this._swappingAudioCodec = false;
                    this._handleStreamError(data);
                }
                break;
            default:
                this._handleStreamError(data);
                break;
        }
    }

    private _handleMediaPlaying = (): void => {
        this._mediaTagPlayPromise = null;
        this._streamStarted();
        this._resolveStreamPromise();
    }

    private _handleAudioError = (): void => {
        if (!this._log) {
            return;
        }
        // Ensure we only emit errors once per stream
        if (this._audio) {
            this._audio.removeEventListener('loadeddata', this._handleMediaPlaying);
            this._audio.removeEventListener('stalled', this._handleAudioError);
            this._audio.removeEventListener('error', this._handleAudioError);
        }
        this._mediaTagPlayPromise = null;
        const code = this._audio && this._audio.error && this._audio.error.code;
        // MEDIA_ERR_ABORTED means the user requested the action
        if (code !== MediaError.MEDIA_ERR_ABORTED) {
            const err = RadioPlayer._getMediaError(code);
            // If PLS, try all the streams until one works or they all fail
            if (this._mode === Mode.PLS) {
                this._nextPLSStream(err);
            } else {
                this._handleStreamError(err);
            }
        }
    }

    private _handleVideoError = (): void => {
        if (!this._log) {
            return;
        }
        // Ensure we only emit errors once per stream
        if (this._video) {
            this._video.removeEventListener('loadeddata', this._handleMediaPlaying);
            this._video.removeEventListener('error', this._handleAudioError);
        }
        this._mediaTagPlayPromise = null;
        const code = this._video && this._video.error && this._video.error.code;
        // MEDIA_ERR_ABORTED means the user requested the action
        if (code !== MediaError.MEDIA_ERR_ABORTED) {
            this._handleStreamError(RadioPlayer._getMediaError(code));
        }
    }

    private static _getMediaError(code: number): string {
        switch (code) {
            case 1: return 'MEDIA_ERR_ABORTED';
            case 2: return 'MEDIA_ERR_NETWORK';
            case 3: return 'MEDIA_ERR_DECODE';
            case 4: return 'MEDIA_ERR_SRC_NOT_SUPPORTED';
            default: return 'UNKNOWN';
        }
    }

    // Returns an unresolved Promise, and keeps track of the Promise and
    // its resolve and reject methods, for use in resolving the Promise in
    // response to emitted events later on. Accepts a method that actually
    // starts the stream
    private _setStreamPromiseHandlers(
        startStream: () => void | Promise<void>,
    ): Promise<void> {
        // If we already have a Promise because we've tried a stream that
        // failed, but we have a failover stream to try, continue to use it,
        // since we've already cancelled the events that might have called
        // resolve or reject, and the skill is already waiting on it.
        if (this._playPromise) {
            startStream();
            return this._playPromise;
        }
        // If we don't have a Promise yet, create one, and store it and its
        // resolve and reject functions for eventual use
        return this._playPromise = this._promises.wrap(
            new Promise<void>((resolve, reject) => {
                this._playReject = reject;
                this._playResolve = resolve;
                startStream();
            }));
    }

    // Calling this will resolve the #play Promise that the skill is awaiting
    private _resolveStreamPromise(): void {
        if (this._playPromise) {
            this._log.info('Resolving play promise');
            this._playResolve();
            this._playPromise = null;
            this._playReject = null;
            this._playResolve = null;
        }
    }

    // Calling this will either reject the #play Promise, or, if the Promise
    // has already been resolved, emit the error so the skill can respond
    private _rejectOrEmit(reason?: any): void {
        if (this._playPromise) {
            this._log.info('Rejecting play promise');
            this._playReject(reason);
            this._playPromise = null;
            this._playReject = null;
            this._playResolve = null;
        } else {
            this.emit('error', `Error while playing stream: ${reason}`);
        }
    }
}
